import 'dart:convert';
import 'package:http/http.dart' as http;

class UpdateService {
  static const _repo = 'lxmw001/music_app';
  static const _currentVersion = String.fromEnvironment('APP_VERSION', defaultValue: '1.0.0+1');

  /// Returns the download URL if a newer release exists, null otherwise.
  Future<String?> checkForUpdate() async {
    try {
      final res = await http.get(
        Uri.parse('https://api.github.com/repos/$_repo/releases/latest'),
        headers: {'Accept': 'application/vnd.github+json'},
      );
      if (res.statusCode != 200) return null;

      final data = jsonDecode(res.body);
      final latestTag = (data['tag_name'] as String).replaceFirst('v', '');
      final assets = data['assets'] as List;
      if (assets.isEmpty) return null;

      if (_isNewer(latestTag, _currentVersion)) {
        return assets.first['browser_download_url'] as String;
      }
    } catch (_) {}
    return null;
  }

  bool _isNewer(String latest, String current) {
    // Compare build numbers (e.g. "1.0.0+5" vs "1.0.0+1")
    int _build(String v) => int.tryParse(v.contains('+') ? v.split('+').last : '0') ?? 0;
    return _build(latest) > _build(current);
  }
}

