      genres: List<String>.from(json['genres'] ?? []),
    );
  }

  Map<String, dynamic> toJson() => {
    'id': id, 'serverId': serverId, 'title': title, 'artist': artist, 'album': album,
    'imageUrl': imageUrl, 'audioUrl': audioUrl,
    'duration': duration.inSeconds, 'genres': genres,
  };
}

